import{m as t,aU as l,z as a,M as i}from"./chunks/framework.LN92DB6A.js";const o=JSON.parse('{"title":"广州办理港澳通行证及签注攻略：自助机、窗口怎么选","description":"从广州去港澳超方便，通行证和签注怎么办？首次办理和续签流程完全不同，本文帮你一次搞清楚。","frontmatter":{"title":"广州办理港澳通行证及签注攻略：自助机、窗口怎么选","tags":["广州","港澳通行证","签注","自助机","港澳游"],"categories":["生活指南"],"date":"2026-06-01T00:00:00.000Z","description":"从广州去港澳超方便，通行证和签注怎么办？首次办理和续签流程完全不同，本文帮你一次搞清楚。","head":[["link",{"rel":"canonical","href":"https://guangzhou.suporka.site/posts/2026/hk-macao-visa"}]]},"headers":[],"relativePath":"posts/2026/hk-macao-visa.md","filePath":"posts/2026/hk-macao-visa.md","lastUpdated":1779868425000}');const r=t({name:"posts/2026/hk-macao-visa.md"},[["render",function(t,o,r,e,s,n){return l(),a("div",null,[...o[0]||(o[0]=[i('<p>广州离香港这么近，周末去趟港澳买买吃吃很方便。但通行证和签注怎么办？很多人搞不清楚&quot;首次办理&quot;和&quot;续签签注&quot;是两回事，跑冤枉路。</p><p>简单说：<strong>第一次办通行证+签注要去窗口；已有通行证续签签注，自助机2分钟搞定。</strong></p><h2 id="先搞清楚两个概念" tabindex="-1">先搞清楚两个概念 <a class="header-anchor" href="#先搞清楚两个概念" aria-label="Permalink to &quot;先搞清楚两个概念&quot;">​</a></h2><ul><li><strong>港澳通行证</strong>：一本证件，相当于你的&quot;港澳身份证&quot;，首次办理必须到窗口</li><li><strong>签注</strong>：贴在通行证上的&quot;入场券&quot;，每次去港澳都需要有效签注。签注用完了可以续签，续签最方便的是自助机</li></ul><h2 id="首次办理通行证-签注" tabindex="-1">首次办理通行证+签注 <a class="header-anchor" href="#首次办理通行证-签注" aria-label="Permalink to &quot;首次办理通行证+签注&quot;">​</a></h2><h3 id="办理条件" tabindex="-1">办理条件 <a class="header-anchor" href="#办理条件" aria-label="Permalink to &quot;办理条件&quot;">​</a></h3><ul><li>广州户籍居民</li><li>持有广州有效居住证的非广州户籍居民（部分情况）</li></ul><h3 id="办理流程" tabindex="-1">办理流程 <a class="header-anchor" href="#办理流程" aria-label="Permalink to &quot;办理流程&quot;">​</a></h3><ol><li><strong>预约</strong>：通过&quot;广州公安&quot;微信公众号、&quot;穗好办&quot;APP 或广东省公安厅出入境管理局网站预约</li><li><strong>准备材料</strong>： <ul><li>身份证原件</li><li>港澳通行证照片回执（可在&quot;粤易拍&quot;线上办理）</li><li>非广州户籍需提供居住证</li></ul></li><li><strong>到现场办理</strong>：按预约时间到出入境受理大厅 <ul><li>取号排队</li><li>采集指纹、拍照</li><li>缴费</li><li>选择领取方式（邮寄或自取）</li></ul></li><li><strong>等待制证</strong>：一般7-10个工作日</li></ol><h3 id="费用" tabindex="-1">费用 <a class="header-anchor" href="#费用" aria-label="Permalink to &quot;费用&quot;">​</a></h3><ul><li>通行证工本费：60元</li><li>签注费用：一次有效签注15元，二次有效签注30元</li></ul><h2 id="续签签注-已有通行证" tabindex="-1">续签签注（已有通行证） <a class="header-anchor" href="#续签签注-已有通行证" aria-label="Permalink to &quot;续签签注（已有通行证）&quot;">​</a></h2><p>这是最常见的情况——通行证在手，签注用完了要续。</p><h3 id="方式一-自助机续签-最快最方便" tabindex="-1">方式一：自助机续签（最快最方便） <a class="header-anchor" href="#方式一-自助机续签-最快最方便" aria-label="Permalink to &quot;方式一：自助机续签（最快最方便）&quot;">​</a></h3><p>整个过程<strong>2-3分钟</strong>搞定：</p><ol><li>找到附近的<strong>自助签注机</strong></li><li>插入港澳通行证</li><li>选择签注类型（个人旅游/团队旅游）</li><li>确认信息</li><li>扫码缴费</li><li>机器现场打印签注，取回通行证</li></ol><p><strong>自助机分布点</strong>：</p><ul><li>各区出入境受理大厅</li><li>部分派出所</li><li>部分政务服务中心</li><li>可通过&quot;广州公安&quot;公众号查询附近网点</li></ul><h3 id="方式二-网上续签" tabindex="-1">方式二：网上续签 <a class="header-anchor" href="#方式二-网上续签" aria-label="Permalink to &quot;方式二：网上续签&quot;">​</a></h3><p>广东户籍居民可通过网上申请续签：</p><ol><li>登录&quot;广东省公安厅出入境政务服务网&quot;或&quot;广州公安&quot;公众号</li><li>选择&quot;港澳个人游再次签注&quot;</li><li>填写信息、在线缴费</li><li>邮寄到家或到窗口自取</li></ol><p>网上续签需要等待制证邮寄，没有自助机快。</p><h3 id="方式三-窗口续签" tabindex="-1">方式三：窗口续签 <a class="header-anchor" href="#方式三-窗口续签" aria-label="Permalink to &quot;方式三：窗口续签&quot;">​</a></h3><p>到出入境受理大厅窗口办理。适合自助机无法识别、需要换证等情况。</p><h2 id="签注类型怎么选" tabindex="-1">签注类型怎么选 <a class="header-anchor" href="#签注类型怎么选" aria-label="Permalink to &quot;签注类型怎么选&quot;">​</a></h2><div class="table-container"><table><thead><tr><th>签注类型</th><th>说明</th><th>适用人群</th></tr></thead><tbody><tr><td>个人旅游（G签）</td><td>可以自由行，不需要跟团</td><td>广州户籍居民</td></tr><tr><td>团队旅游（L签）</td><td>现在也可以自由行，不需要跟团</td><td>所有居民</td></tr><tr><td>商务签注（S签）</td><td>因商务需要赴港澳</td><td>企业人员</td></tr><tr><td>探亲签注（T签）</td><td>探望在港澳定居的亲属</td><td>有亲属在港澳</td></tr></tbody></table></div><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>现在L签（团队旅游）和G签（个人旅游）的实际使用已经没有区别了，都可以自由行。非广州户籍如果办不了G签，办L签也一样。</p></div><h2 id="签注有效期和次数" tabindex="-1">签注有效期和次数 <a class="header-anchor" href="#签注有效期和次数" aria-label="Permalink to &quot;签注有效期和次数&quot;">​</a></h2><ul><li><strong>签注有效期</strong>：一般为3个月或1年</li><li><strong>签注次数</strong>：一次签注只能去一次港澳，用完需要续签</li><li><strong>每次逗留时间</strong>：香港一般7天，澳门一般7天</li></ul><h2 id="带小孩-老人办理" tabindex="-1">带小孩/老人办理 <a class="header-anchor" href="#带小孩-老人办理" aria-label="Permalink to &quot;带小孩/老人办理&quot;">​</a></h2><h3 id="未满16周岁" tabindex="-1">未满16周岁 <a class="header-anchor" href="#未满16周岁" aria-label="Permalink to &quot;未满16周岁&quot;">​</a></h3><ul><li>需要<strong>监护人陪同</strong>办理</li><li>携带：小孩身份证（或户口簿）、出生证明、监护人身份证</li><li>首次办理必须到窗口</li></ul><h3 id="_60岁以上老人" tabindex="-1">60岁以上老人 <a class="header-anchor" href="#_60岁以上老人" aria-label="Permalink to &quot;60岁以上老人&quot;">​</a></h3><ul><li>可以代办（需携带双方身份证和委托书）</li><li>部分受理大厅有优先窗口</li></ul><h2 id="避坑提醒" tabindex="-1">避坑提醒 <a class="header-anchor" href="#避坑提醒" aria-label="Permalink to &quot;避坑提醒&quot;">​</a></h2><ul><li><strong>通行证有效期不足6个月要先换证</strong>：签注不能在快过期的通行证上办，先换证再签注</li><li><strong>自助机只能续签不能首次办</strong>：第一次办通行证必须到窗口，别跑错</li><li><strong>签注次数用完要续签</strong>：去之前检查签注是否有效，别到了关口才发现没签注</li><li><strong>周末自助机可能排队</strong>：尤其是天河、越秀等热门区域的自助机，工作日去人少</li><li><strong>签注有有效期</strong>：签注办好后有3个月或1年有效期，过期要重新签注</li><li><strong>港澳通行证可以代办续签</strong>：本人不去也能办，但自助机需要插卡操作</li><li><strong>照片回执提前办</strong>：首次办理需要照片回执，建议提前在&quot;粤易拍&quot;线上搞定</li></ul><p>在广州办港澳通行证已经非常方便了。首次办理跑一趟窗口，后面续签自助机随到随办，周末说走就走。</p>',37)])])}]]);export{o as __pageData,r as default};
